<?php
/** Driver trip history with status trail. */
declare(strict_types=1);
require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/driver_functions.php';requireAuth();enforceModuleAccess('drivers');$driver=getDriverById((int)($_GET['id']??0));if(!$driver){redirect('modules/drivers/index.php');}$query=getDb()->prepare('SELECT trip_number,origin,destination,start_date,end_date,status,revenue FROM trips WHERE driver_id=? ORDER BY start_date DESC');$query->execute([$driver['id']]);$trips=$query->fetchAll();$pageTitle='Driver history';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content driver-module"><?php require ROOT_PATH.'/includes/navbar.php';?><h1 class="page-title">Trip history · <?=e($driver['full_name'])?></h1><section class="card table-card"><div class="table-responsive"><table><thead><tr><th>Trip</th><th>Route</th><th>Date</th><th>Status</th><th>Revenue</th></tr></thead><tbody><?php foreach($trips as $trip):?><tr><td><?=e($trip['trip_number'])?></td><td><?=e($trip['origin'].' → '.$trip['destination'])?></td><td><?=e(formatDate($trip['start_date']))?></td><td><?=e($trip['status'])?></td><td><?=e(formatCurrency((float)$trip['revenue']))?></td></tr><?php endforeach;?></tbody></table></div></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
